import{_ as a,o as s,c as i,ag as t}from"./chunks/framework.ePeAWSvT.js";const u=JSON.parse('{"title":"Installation","description":"Installation details, runtime expectations, and production build commands for Foldergram.","frontmatter":{"title":"Installation","description":"Installation details, runtime expectations, and production build commands for Foldergram."},"headers":[],"relativePath":"installation.md","filePath":"installation.md","lastUpdated":1774719654000}'),o={name:"installation.md"};function l(d,e,n,r,p,h){return s(),i("div",null,[...e[0]||(e[0]=[t(`<h1 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to &quot;Installation&quot;">​</a></h1><h2 id="recommended-docker-compose" tabindex="-1">Recommended: Docker Compose <a class="header-anchor" href="#recommended-docker-compose" aria-label="Permalink to &quot;Recommended: Docker Compose&quot;">​</a></h2><p>For most people, Docker Compose is the best way to install Foldergram.</p><p>It uses the pre-built container image and already includes the media tooling needed for video support.</p><h3 id="_1-create-a-working-folder" tabindex="-1">1. Create a working folder <a class="header-anchor" href="#_1-create-a-working-folder" aria-label="Permalink to &quot;1. Create a working folder&quot;">​</a></h3><p>Create a folder for Foldergram and move into it:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mkdir</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> foldergram</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> foldergram</span></span></code></pre></div><h3 id="_2-create-docker-compose-yml" tabindex="-1">2. Create <code>docker-compose.yml</code> <a class="header-anchor" href="#_2-create-docker-compose-yml" aria-label="Permalink to &quot;2. Create \`docker-compose.yml\`&quot;">​</a></h3><p>Download the Compose file:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">wget</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -O</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> docker-compose.yml</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://raw.githubusercontent.com/foldergram/foldergram/main/docker-compose.yml</span></span></code></pre></div><h3 id="_3-create-your-first-gallery-folder" tabindex="-1">3. Create your first gallery folder <a class="header-anchor" href="#_3-create-your-first-gallery-folder" aria-label="Permalink to &quot;3. Create your first gallery folder&quot;">​</a></h3><p>Create a starter folder for your first indexed App Folder:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mkdir</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> data/gallery/example-album</span></span></code></pre></div><p>The layout should look like this:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>foldergram/</span></span>
<span class="line"><span>  docker-compose.yml</span></span>
<span class="line"><span>  data/</span></span>
<span class="line"><span>    gallery/</span></span>
<span class="line"><span>      example-album/</span></span></code></pre></div><h3 id="_4-add-your-media" tabindex="-1">4. Add your media <a class="header-anchor" href="#_4-add-your-media" aria-label="Permalink to &quot;4. Add your media&quot;">​</a></h3><p>Place photos and videos inside <code>data/gallery/example-album</code> or another folder under <code>data/gallery</code>.</p><p>Foldergram ignores loose files placed directly in the gallery root, so use a structure like this:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>data/</span></span>
<span class="line"><span>  gallery/</span></span>
<span class="line"><span>    trips/</span></span>
<span class="line"><span>      oslo/</span></span>
<span class="line"><span>        IMG_0001.jpg</span></span>
<span class="line"><span>        clip-01.mp4</span></span>
<span class="line"><span>    family/</span></span>
<span class="line"><span>      summer-2024/</span></span>
<span class="line"><span>        porch.webp</span></span></code></pre></div><h3 id="_5-start-foldergram" tabindex="-1">5. Start Foldergram <a class="header-anchor" href="#_5-start-foldergram" aria-label="Permalink to &quot;5. Start Foldergram&quot;">​</a></h3><p>Run:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> compose</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> up</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span></span></code></pre></div><h3 id="_6-open-the-app" tabindex="-1">6. Open the app <a class="header-anchor" href="#_6-open-the-app" aria-label="Permalink to &quot;6. Open the app&quot;">​</a></h3><p>Open:</p><ul><li><code>http://localhost:4141</code></li></ul><p>For a quick backend check, you can also open:</p><ul><li><code>http://localhost:4141/api/health</code></li></ul><p>The default Compose file uses the GHCR image and exposes <code>4141:4141</code>. If you need a different host port, edit the left side of that mapping in <code>docker-compose.yml</code>.</p><p>In the default Docker Compose setup, the container uses the image&#39;s built-in production defaults plus the mounted <code>./data/...</code> volumes. The source-install <code>.env</code> file is not read directly inside the container.</p><p>The shipped Compose file includes <code>IMAGE_DETAIL_SOURCE: preview</code> and <code>DERIVATIVE_MODE: eager</code>.</p><p>If you want lazy derivatives or original-backed image detail pages, edit those values in <code>docker-compose.yml</code> before starting the container.</p><p>For an optional read-only public demo in Docker, add <code>PUBLIC_DEMO_MODE: &quot;1&quot;</code> under the Compose <code>environment:</code> block. If the browser-visible origin differs from the upstream Node host, also set <code>CSRF_TRUSTED_ORIGINS</code> to that public origin.</p><p>If the app will be reachable from other devices on your network, enable the admin password from the Settings page after first startup. You can then keep the app admin-only, add a separate viewer password, or switch to public browse mode with admin unlock.</p><h2 id="if-you-already-cloned-this-repository" tabindex="-1">If you already cloned this repository <a class="header-anchor" href="#if-you-already-cloned-this-repository" aria-label="Permalink to &quot;If you already cloned this repository&quot;">​</a></h2><p>This repository includes:</p><ul><li><code>docker-compose.yml</code> for the GHCR image</li><li><code>docker-compose.local.yml</code> as a local-build override</li></ul><p>From the repo root, run:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> compose</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> docker-compose.yml</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> docker-compose.local.yml</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> up</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --build</span></span></code></pre></div><p>This command uses the normal runtime settings, but builds the image locally from the repository <code>Dockerfile</code>.</p><h2 id="source-install-for-development" tabindex="-1">Source install for development <a class="header-anchor" href="#source-install-for-development" aria-label="Permalink to &quot;Source install for development&quot;">​</a></h2><p>Use the source install when you want to develop Foldergram itself.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .env.example</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .env</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dev</span></span></code></pre></div><p>The shipped <code>.env.example</code> keeps the development ports aligned like this:</p><ul><li><code>DEV_CLIENT_PORT=4141</code> with client fallback through <code>4144</code></li><li><code>DEV_SERVER_PORT=4140</code></li></ul><h2 id="runtime-requirements-for-source-installs" tabindex="-1">Runtime requirements for source installs <a class="header-anchor" href="#runtime-requirements-for-source-installs" aria-label="Permalink to &quot;Runtime requirements for source installs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Requirement</th><th>Why it matters</th></tr></thead><tbody><tr><td>Node.js 22</td><td>Used across the workspace and CI configuration.</td></tr><tr><td><code>pnpm</code></td><td>Matches the workspace scripts and lockfile.</td></tr><tr><td>Writable local storage</td><td>Foldergram creates and maintains the gallery, database, thumbnails, and previews directories.</td></tr><tr><td>FFmpeg and FFprobe</td><td>Needed only when you run the app outside Docker and want supported video processing. The backend calls <code>ffprobe</code> for metadata and <code>ffmpeg</code> for video thumbnails and previews.</td></tr></tbody></table><h2 id="supported-media" tabindex="-1">Supported media <a class="header-anchor" href="#supported-media" aria-label="Permalink to &quot;Supported media&quot;">​</a></h2><h3 id="images" tabindex="-1">Images <a class="header-anchor" href="#images" aria-label="Permalink to &quot;Images&quot;">​</a></h3><ul><li><code>.jpg</code></li><li><code>.jpeg</code></li><li><code>.png</code></li><li><code>.webp</code></li><li><code>.gif</code></li></ul><h3 id="videos" tabindex="-1">Videos <a class="header-anchor" href="#videos" aria-label="Permalink to &quot;Videos&quot;">​</a></h3><ul><li><code>.mp4</code></li><li><code>.mov</code></li><li><code>.m4v</code></li><li><code>.webm</code></li><li><code>.mkv</code></li></ul><h2 id="default-local-paths" tabindex="-1">Default local paths <a class="header-anchor" href="#default-local-paths" aria-label="Permalink to &quot;Default local paths&quot;">​</a></h2><p>The shipped <code>.env.example</code> points at:</p><table tabindex="0"><thead><tr><th>Variable</th><th>Default</th></tr></thead><tbody><tr><td><code>DATA_ROOT</code></td><td><code>./data</code></td></tr><tr><td><code>GALLERY_ROOT</code></td><td><code>./data/gallery</code></td></tr><tr><td><code>DB_DIR</code></td><td><code>./data/db</code></td></tr><tr><td><code>THUMBNAILS_DIR</code></td><td><code>./data/thumbnails</code></td></tr><tr><td><code>PREVIEWS_DIR</code></td><td><code>./data/previews</code></td></tr></tbody></table><p><code>DATA_ROOT</code> is the base path for this layout. If you change only <code>DATA_ROOT</code>, Foldergram will look for <code>gallery</code>, <code>db</code>, <code>thumbnails</code>, and <code>previews</code> under that directory unless you override those paths individually.</p><p>Foldergram resolves relative paths from the repository root.</p><h2 id="production-behavior" tabindex="-1">Production behavior <a class="header-anchor" href="#production-behavior" aria-label="Permalink to &quot;Production behavior&quot;">​</a></h2><h3 id="docker" tabindex="-1">Docker <a class="header-anchor" href="#docker" aria-label="Permalink to &quot;Docker&quot;">​</a></h3><p>The Docker Compose install already runs the app in production mode. The app inside the container listens on <code>4141</code> by default.</p><h3 id="source" tabindex="-1">Source <a class="header-anchor" href="#source" aria-label="Permalink to &quot;Source&quot;">​</a></h3><p>The production app build is split from the docs build:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> start</span></span></code></pre></div><p><code>pnpm build</code> builds:</p><ul><li><code>server</code></li><li><code>client</code></li></ul><p>It does <strong>not</strong> build the docs site.</p><h3 id="how-production-serving-works" tabindex="-1">How production serving works <a class="header-anchor" href="#how-production-serving-works" aria-label="Permalink to &quot;How production serving works&quot;">​</a></h3><p>When <code>NODE_ENV=production</code>, the Express app serves <code>client/dist</code> if it exists. Requests that do not start with <code>/api</code>, <code>/thumbnails</code>, or <code>/previews</code> fall back to the SPA entry point.</p><h2 id="docs-build" tabindex="-1">Docs build <a class="header-anchor" href="#docs-build" aria-label="Permalink to &quot;Docs build&quot;">​</a></h2><p>The VitePress site is built separately:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build:docs</span></span></code></pre></div><p>The deploy workflow publishes <code>./docs/.vitepress/dist</code>.</p><h2 id="optional-developer-entry-points" tabindex="-1">Optional developer entry points <a class="header-anchor" href="#optional-developer-entry-points" aria-label="Permalink to &quot;Optional developer entry points&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dev:server</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dev:client</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dev:docs</span></span></code></pre></div><h2 id="first-run-behavior" tabindex="-1">First-run behavior <a class="header-anchor" href="#first-run-behavior" aria-label="Permalink to &quot;First-run behavior&quot;">​</a></h2><p>On startup, the server checks storage availability and then decides whether to:</p><ul><li>queue a startup scan</li><li>keep using the existing index</li><li>block scanning until a library rebuild happens after a gallery root change</li></ul><p>If the configured database directory is unavailable, Foldergram falls back to an in-memory SQLite database. If the gallery, thumbnails, or previews directories are unavailable, the library is reported as unavailable instead of serving stale filesystem assumptions.</p>`,77)])])}const k=a(o,[["render",l]]);export{u as __pageData,k as default};
